#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

kernel void lud_diagonal(global float* a, local float* temp, const int size, const int offset) {
    int i = get_global_id(0);

    if (i >= BLOCK_SIZE) return;

    // Load diagonal block into local memory
    for (int j = 0; j < BLOCK_SIZE; j++) {
        temp[i * BLOCK_SIZE + j] = a[(offset + i) * size + (offset + j)];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Sequential LU decomposition on diagonal block
    for (int row = 0; row < BLOCK_SIZE; row++) {
        if (i == row) {
            // Update upper triangle
            for (int j = row; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (int k = 0; k < row; k++) {
                    sum += temp[row * BLOCK_SIZE + k] * temp[k * BLOCK_SIZE + j];
                }
                temp[row * BLOCK_SIZE + j] -= sum;
            }

            // Compute diagonal inverse
            float diag_inv = 1.0f / temp[row * BLOCK_SIZE + row];

            // Update lower triangle
            for (int j = row + 1; j < BLOCK_SIZE; j++) {
                float sum = 0.0f;
                for (int k = 0; k < row; k++) {
                    sum += temp[j * BLOCK_SIZE + k] * temp[k * BLOCK_SIZE + row];
                }
                temp[j * BLOCK_SIZE + row] = (temp[j * BLOCK_SIZE + row] - sum) * diag_inv;
            }
        }
        barrier(CLK_LOCAL_MEM_FENCE);
    }

    // Write back to global memory
    for (int j = 0; j < BLOCK_SIZE; j++) {
        a[(offset + i) * size + (offset + j)] = temp[i * BLOCK_SIZE + j];
    }
}

kernel void lud_perimeter(global float* a, local float* temp_top, local float* temp_left, local float* temp_diag,
                          const int size, const int offset) {
    int idx = get_global_id(0);
    int num_blocks = (size - offset) / BLOCK_SIZE - 1;

    if (idx >= BLOCK_SIZE * 2 * num_blocks) return;

    int section = idx / (BLOCK_SIZE * num_blocks);
    int block_id = (idx / BLOCK_SIZE) % num_blocks;
    int elem_id = idx % BLOCK_SIZE;

    if (section == 0) {
        // Right perimeter: blocks to the right of diagonal
        int col_offset = offset + BLOCK_SIZE + block_id * BLOCK_SIZE;

        // Load diagonal block row
        for (int j = 0; j < BLOCK_SIZE; j++) {
            temp_diag[elem_id * BLOCK_SIZE + j] = a[(offset + elem_id) * size + (offset + j)];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        // Load right block
        for (int j = 0; j < BLOCK_SIZE; j++) {
            temp_top[elem_id * BLOCK_SIZE + j] = a[(offset + elem_id) * size + (col_offset + j)];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        // Update: subtract product of diagonal row and corresponding values
        for (int k = 0; k < elem_id; k++) {
            for (int j = 0; j < BLOCK_SIZE; j++) {
                temp_top[elem_id * BLOCK_SIZE + j] -= temp_diag[elem_id * BLOCK_SIZE + k] * temp_diag[k * BLOCK_SIZE + j];
            }
        }

        // Write back
        for (int j = 0; j < BLOCK_SIZE; j++) {
            a[(offset + elem_id) * size + (col_offset + j)] = temp_top[elem_id * BLOCK_SIZE + j];
        }
    } else {
        // Bottom perimeter: blocks below diagonal
        int row_offset = offset + BLOCK_SIZE + block_id * BLOCK_SIZE;

        // Load diagonal block
        for (int j = 0; j < BLOCK_SIZE; j++) {
            temp_diag[elem_id * BLOCK_SIZE + j] = a[(offset + elem_id) * size + (offset + j)];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        // Load bottom block
        for (int j = 0; j < BLOCK_SIZE; j++) {
            temp_left[elem_id * BLOCK_SIZE + j] = a[(row_offset + elem_id) * size + (offset + j)];
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        float diag_inv = 1.0f / temp_diag[elem_id * BLOCK_SIZE + elem_id];

        // Update: subtract and divide by diagonal
        for (int k = 0; k < elem_id; k++) {
            for (int j = 0; j < BLOCK_SIZE; j++) {
                temp_left[elem_id * BLOCK_SIZE + j] -= temp_diag[elem_id * BLOCK_SIZE + k] * temp_diag[k * BLOCK_SIZE + j];
            }
        }

        // Write back
        for (int j = 0; j < BLOCK_SIZE; j++) {
            a[(row_offset + elem_id) * size + (offset + j)] = temp_left[elem_id * BLOCK_SIZE + j] * diag_inv;
        }
    }
}

kernel void lud_internal(global float* a, local float* temp_top, local float* temp_left,
                         const int size, const int offset) {
    int x = get_global_id(0);
    int y = get_global_id(1);

    int num_blocks = (size - offset) / BLOCK_SIZE - 1;

    if (x >= BLOCK_SIZE * num_blocks || y >= BLOCK_SIZE * num_blocks) return;

    int block_x = x / BLOCK_SIZE;
    int block_y = y / BLOCK_SIZE;
    int elem_x = x % BLOCK_SIZE;
    int elem_y = y % BLOCK_SIZE;

    int row_offset = offset + BLOCK_SIZE + block_x * BLOCK_SIZE;
    int col_offset = offset + BLOCK_SIZE + block_y * BLOCK_SIZE;

    // Load from diagonal row block
    for (int j = 0; j < BLOCK_SIZE; j++) {
        temp_top[elem_x * BLOCK_SIZE + j] = a[(offset + elem_x) * size + (col_offset + j)];
    }

    // Load from diagonal column block
    for (int j = 0; j < BLOCK_SIZE; j++) {
        temp_left[elem_x * BLOCK_SIZE + j] = a[(row_offset + elem_x) * size + (offset + j)];
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Update internal block element
    float sum = 0.0f;
    for (int k = 0; k < BLOCK_SIZE; k++) {
        sum += temp_left[elem_x * BLOCK_SIZE + k] * temp_top[k * BLOCK_SIZE + elem_y];
    }

    a[(row_offset + elem_x) * size + (col_offset + elem_y)] -= sum;
}
